    def __init__(self):
        self.plan_history = []

    async def on_plan_generated(self, plan: str, functions: list) -> bool:
        invoked_plugins = {f.plugin_name for f in functions}
        sensitive_calls = invoked_plugins & self.SENSITIVE_PLUGINS
        if sensitive_calls:
            self.plan_history.append({
                'timestamp': datetime.now(),
                'plan': plan,
                'risky_plugins': list(sensitive_calls)
            })
            return False  # Block execution
        return True
