from semantic_kernel.memory import SemanticTextMemory

JAILBREAK_PATTERNS = [
    r'ignore.*previous.*instructions',
    r'developers?\s*mode',
    r'override.*safety',
    r'you\s*are\s*(god|root|admin)'
]

def scan_memory_for_jailbreaks(memory: SemanticTextMemory, query: str):
    collections = memory.store.collections
    risky_collections = []
    for collection in collections:
        records = memory.search(collection.name, query, limit=5)
        for record in records:
            for pattern in JAILBREAK_PATTERNS:
                if re.search(pattern, record.text, re.IGNORECASE):
                    risky_collections.append(collection.name)
    return risky_collections
