const JAILBREAK_KEYWORDS = ['DAN', 'ignore safety', 'system override'];

function validatePluginInput(input: string): boolean {
  return !JAILBREAK_KEYWORDS.some(keyword => 
    input.toLowerCase().includes(keyword.toLowerCase())
  );
}

const securePluginFilter = (func: KernelFunction) => {
  return async (...args: any[]) => {
    const input = args[0]?.toString();
    if (!validatePluginInput(input)) {
      throw new Error('Jailbreak attempt detected in plugin input');
    }
    return await func(...args);
  };
