from semantic_kernel.planners.handlebars import HandlebarsPlanner

class SecureHandlebarsPlanner(HandlebarsPlanner):
    SAFE_TEMPLATES = [
        '{{#foreach $functions}}',
        '{{name}}',
        '{{description}}'
    ]

    def _render_template(self, template: str, context: dict) -> str:
        for safe_pattern in self.SAFE_TEMPLATES:
            if safe_pattern not in template:
                raise ValueError('Unsafe Handlebars template detected')
        return super()._render_template(template, context)

secure_planner = SecureHandlebarsPlanner(kernel)
