import { Kernel } from '@microsoft/semantic-kernel';

type SafePluginInput<T> = {
  [K in keyof T]: string | number | boolean;
};

const createSafePlugin = <T>(plugin: KernelPlugin<T>) => {
  return {
    ...plugin,
    invoke: async (funcName: keyof T, input: SafePluginInput<T>) => {
      // Validate input types before invocation
      const validatedInput = Object.fromEntries(
        Object.entries(input).filter(([key]) => 
          typeof input[key as keyof T] !== 'object'
        )
      ) as SafePluginInput<T>;

      return await plugin.invoke(funcName, validatedInput);
    }
  };
};
